import React from "react";
import { useState } from "react";
import { useDispatch, useSelector } from "react-redux"
import { useEffect } from "react";
import itinerariesActions from "../redux/actions/itinerariesActions";
import commentsActions from "../redux/actions/commentsActions"
import TextField from '@mui/material/TextField';
import Box from '@mui/material/Box';
import SendIcon from '@mui/icons-material/Send';

import DeleteIcon from "@mui/icons-material/Delete"
import EditIcon from '@mui/icons-material/Edit'
import AddIcon from '@mui/icons-material/Add'

function Comments ({itinerary, cityid}){
    const [comments, setComments] = useState([])
    const [inputText, setInputText] = useState("") 
    const [modifyComment, setModifyComment] = useState("") 
    const [reload, setReload] = useState()
    
    const dispatch = useDispatch()

    const user = useSelector(store => store.userReducers.user)
    // console.log(user.id);


    // comment functions


    async function addComment(){
        const commentData = {
            itineraryId: itinerary._id,
            comments :{
                comment: inputText,
                userID: user.id
            }
        }
        await dispatch(commentsActions.addComment(commentData))
        setInputText("")
        setReload(!reload)
    }


    async function modifyComments(comments){
        const commentData = {
            commentId: comments._id,
            comment: modifyComment
        }
        await dispatch(commentsActions.modifyComment(commentData))
        setReload(!reload)
    }


    async function deleteComment(comments){
        await dispatch(commentsActions.deleteComment(comments._id))
        setReload(!reload)
    }


    useEffect(() => {
        dispatch(itinerariesActions.findTinFromCity(cityid))
    }, [reload])

    return(
        <>
        {itinerary.comments.length>0?
                    itinerary.comments.map(comments=>(
                        <div className="comment" key={comments._id}>
                            <p>{comments.comment}</p>
                            <p>{comments.date}</p>
                            <DeleteIcon id={comments._id} onClick={() => deleteComment(comments)} />
                            <textarea rows='2' onChange={(event) => setModifyComment(event.target.value)} defaultValue={comments.comment} className='myInputforComment fredokaFont' />
                                        <EditIcon id={comments._id} onClick={() => modifyComments(comments)} sx={{bgcolor: 'rgb(196, 165, 126)', '&:hover': {bgcolor: 'rgba(196, 165, 126, 0.7)'}, padding: '5px', margin: '5px', color: 'white', width: '30px', height: '30px', borderRadius: '15px'}} />
                        </div>
                        
                    )):
                    <div>
                        <h1>there are no commentaries, be the first</h1>
                    </div>
                }
                
                <Box
                    sx={{width: 500, maxWidth: '100%',}}>
                    <TextField fullWidth placeholder="Comment!" id="fullWidth" onChange={(event) => setInputText(event.target.value)} value={inputText}/>
                </Box>

        <textarea rows='2' onChange={(event) => setInputText(event.target.value)} value={inputText} className='myInputforComment fredokaFont' />
                            <AddIcon onClick={addComment} sx={{bgcolor: 'rgb(196, 165, 126)', '&:hover': {bgcolor: 'rgba(196, 165, 126, 0.7)'}, padding: '5px', margin: '5px', marginRigth: '0', color: 'white', width: '30px', height: '30px', borderRadius: '15px'}} />
        </>
    )
}
export default Comments
